if (pb.type === 'article') {
badge.className = 'badge-glow badge-glow-article'
badge.textContent = 'ARTICLE'
} else {
badge.className = 'badge-glow badge-glow-playbook'
badge.textContent = 'PLAYBOOK'
}
document.getElementById('playbook-detail-title').textContent = name
document.getElementById('playbook-detail-subtitle').textContent = pb.subtitle
document.getElementById('playbook-tag-1').textContent = pb.tag
document.getElementById('playbook-about-text').textContent = pb.about
var learnsList = document.getElementById('playbook-learns-list')
learnsList.innerHTML = pb.learns.map(function(item) {
return '<li class="flex items-start gap-2"><span class="text-violet-400 mt-0.5">&#10003;</span> ' + item + '</li>'
}).join('')
var tagsEl = document.getElementById('playbook-tags')
tagsEl.innerHTML = pb.tags.map(function(t) {
return '<span style="background:var(--bg-tag); color:var(--text-tag);" class="text-xs px-2.5 py-1 rounded">' + t + '</span>'
}).join('')
document.getElementById('playbook-content').innerHTML = pb.content
var readTime = estimateReadingTime(pb.content)
document.getElementById('playbook-reading-time').textContent = readTime + ' min read'
var tocEl = document.getElementById('playbook-toc-links')
var contentEl = document.getElementById('playbook-content')
var headings = contentEl.querySelectorAll('h2')
if (headings.length > 0) {
tocEl.innerHTML = ''
headings.forEach(function(h, i) {
h.id = 'pb-section-' + i
var link = document.createElement('a')
link.className = 'playbook-toc-link'
link.textContent = h.textContent
link.onclick = function() { h.scrollIntoView({ behavior: 'smooth', block: 'start' }); }
tocEl.appendChild(link)
})
} else {
tocEl.innerHTML = '<span style="color:var(--text-muted); font-size:12px;">No sections</span>'
}
var pbNames = Object.keys(playbookData)
var related = pbNames.filter(function(n) { return n !== name; }).slice(0, 3).map(function(n) {
var item = playbookData[n]
return { type: item.type === 'article' ? 'ARTICLE' : 'PLAYBOOK', view: 'playbook-detail', name: n, desc: item.subtitle.substring(0, 60) + '...' }
})
